import { useMemo, useState } from "react";
import AppShell from "../components/AppShell";
import DataTable from "../components/DataTable";
import EmptyState from "../components/EmptyState";
import InsightPanel from "../components/InsightPanel";
import MetricCard from "../components/MetricCard";
import PageHeader from "../components/PageHeader";
import SearchFilterBar from "../components/SearchFilterBar";
import SectionCard from "../components/SectionCard";
import SegmentTabs from "../components/SegmentTabs";
import { useVitalPulse } from "../context/VitalPulseContext";
import { formatDateTime } from "../utils/formatters";

export default function AlertsPage() {
  const { alerts, latestReading, derived } = useVitalPulse();
  const [tab, setTab] = useState("All");
  const [search, setSearch] = useState("");
  const selectedAlert = alerts[0] || null;

  const summary = useMemo(() => ({
    critical: alerts.filter((item) => String(item.severity).toLowerCase() === "critical").length,
    warning: alerts.filter((item) => String(item.severity).toLowerCase() === "warning").length,
    acknowledged: alerts.filter((item) => String(item.status).toLowerCase() === "acknowledged").length,
    resolved: alerts.filter((item) => String(item.status).toLowerCase() === "resolved").length,
  }), [alerts]);

  return (
    <AppShell>
      <PageHeader
        title="Alerts"
        subtitle="Review, acknowledge, and monitor abnormal vital-sign events."
        tabs={
          <SegmentTabs
            tabs={["All", "Critical", "Warning", "Open", "Acknowledged", "Resolved"]}
            value={tab}
            onChange={setTab}
          />
        }
        filters={
          <SearchFilterBar
            searchValue={search}
            onSearchChange={setSearch}
            searchPlaceholder="Search by patient ID or device ID"
            filters={[
              { label: "Severity", value: "all", onChange: () => {}, disabled: true, options: [{ value: "all", label: "Alert filtering endpoint required" }] },
              { label: "Alert type", value: "all", onChange: () => {}, disabled: true, options: [{ value: "all", label: "Alert filtering endpoint required" }] },
              { label: "Status", value: "all", onChange: () => {}, disabled: true, options: [{ value: "all", label: "Alert filtering endpoint required" }] },
            ]}
            onClear={() => setSearch("")}
          />
        }
      />

      <div className="vp-grid vp-grid-metrics">
        <MetricCard icon="alerts" label="Open alerts" value={alerts.length} helper="Current feed size" status={alerts.length ? "Open" : "Resolved"} />
        <MetricCard icon="risk" label="Critical alerts" value={summary.critical} helper="Severity derived from feed" status={summary.critical ? "Critical" : "Resolved"} />
        <MetricCard icon="alerts" label="Warning alerts" value={summary.warning} helper="Severity derived from feed" status={summary.warning ? "Warning" : "Resolved"} />
        <MetricCard icon="clock" label="Acknowledged alerts" value={summary.acknowledged} helper="Backend acknowledgement workflow missing" status="Pending" />
        <MetricCard icon="dashboard" label="Resolved alerts" value={summary.resolved} helper="Current feed returns empty array by default" status="Resolved" />
        <MetricCard icon="history" label="Average response time" value="Endpoint required" helper="No audit or workflow timestamps yet" status="Pending" />
      </div>

      <div className="vp-content-with-panel">
        <div className="vp-content-main">
          <SectionCard title="Alert Management Centre" subtitle="Clinical anomalies, severity, explanation, and operator actions.">
            <DataTable
              columns={[
                { key: "id", label: "Alert ID" },
                { key: "patientId", label: "Patient" },
                { key: "deviceId", label: "Device" },
                { key: "type", label: "Type" },
                { key: "severity", label: "Severity", type: "badge" },
                { key: "reason", label: "Reason" },
                { key: "triggeredAt", label: "Triggered time", render: (value) => formatDateTime(value) },
                { key: "mlReason", label: "ML reason" },
                { key: "status", label: "Status", type: "badge" },
              ]}
              rows={alerts}
              emptyTitle="No alerts available"
              emptyMessage="The alerts endpoint is reachable but currently returns no alert events."
            />
          </SectionCard>
        </div>
        <InsightPanel
          title="Alert Detail Panel"
          subtitle="Selected alert context, clinical summary, and action readiness."
          items={[
            { label: "Selected alert", value: selectedAlert?.id || "No alert selected", status: selectedAlert?.severity || "Pending" },
            { label: "Full reason", value: selectedAlert?.reason || "No alert feed item available", status: selectedAlert?.status || "Pending" },
            { label: "Latest vitals", value: latestReading ? `${latestReading.heart_rate} bpm | ${latestReading.temperature} deg C | ${latestReading.spo2}%` : "No current reading", status: latestReading ? "Loaded" : "Pending" },
            { label: "Risk explanation", value: derived.mlAvailable ? `Score ${latestReading?.anomaly_score}` : "Model endpoint required", status: derived.riskLabel },
            { label: "Timeline", value: selectedAlert ? formatDateTime(selectedAlert.triggeredAt) : "No event history", status: selectedAlert ? "Loaded" : "Pending" },
            { label: "Actions", value: "Acknowledge, escalate, and notes need backend endpoints", status: "Pending" },
          ]}
          footer="Alert actions remain disabled because the backend only exposes a read-only empty alert feed today."
        />
      </div>
    </AppShell>
  );
}
